            ...selectedItems.slice(selectedItemIndex + 1),
          ],
          activeIndex: newActiveIndex,
        }
      }
      break
    }
    case stateChangeTypes.FunctionSetSelectedItems: {
      const {selectedItems: newSelectedItems} = action
      changes = {
        selectedItems: newSelectedItems,
